import os
import boto3
import time
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from selenium.webdriver.chrome.service import Service
from PIL import Image
from io import BytesIO
import hashlib
from datetime import datetime
from flask import Flask, request, jsonify
import logging

app = Flask(__name__)
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

AWS_REGION = os.environ.get('AWS_REGION', 'us-east-1')
S3_BUCKET = os.environ.get('S3_BUCKET', 'screenshot-bucket')
SCREENSHOT_WIDTH = int(os.environ.get('SCREENSHOT_WIDTH', '1280'))
SCREENSHOT_HEIGHT = int(os.environ.get('SCREENSHOT_HEIGHT', '720'))
THUMBNAIL_WIDTH = int(os.environ.get('THUMBNAIL_WIDTH', '400'))
THUMBNAIL_HEIGHT = int(os.environ.get('THUMBNAIL_HEIGHT', '300'))

s3_client = boto3.client('s3', region_name=AWS_REGION)


class ScreenshotService:
    def __init__(self):
        self.driver = None
        self.setup_driver()

    def setup_driver(self):
        chrome_options = Options()
        chrome_options.add_argument('--headless')
        chrome_options.add_argument('--no-sandbox')
        chrome_options.add_argument('--disable-dev-shm-usage')
        chrome_options.add_argument('--disable-gpu')
        chrome_options.add_argument('--window-size={},{}'.format(SCREENSHOT_WIDTH, SCREENSHOT_HEIGHT))
        chrome_options.add_argument('--disable-extensions')
        chrome_options.add_argument('--disable-infobars')
        chrome_options.add_argument('--disable-notifications')
        chrome_options.add_argument('--ignore-certificate-errors')
        chrome_options.add_argument('--user-agent=Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36')

        try:
            self.driver = webdriver.Chrome(options=chrome_options)
            self.driver.set_page_load_timeout(30)
            logger.info("Chrome driver initialized successfully")
        except Exception as e:
            logger.error(f"Failed to initialize Chrome driver: {e}")
            raise

    def capture_screenshot(self, url):
        try:
            logger.info(f"Capturing screenshot for URL: {url}")
            self.driver.get(url)
            time.sleep(2)
            
            screenshot_bytes = self.driver.get_screenshot_as_png()
            
            return screenshot_bytes
        except Exception as e:
            logger.error(f"Error capturing screenshot: {e}")
            raise

    def create_thumbnail(self, screenshot_bytes):
        try:
            image = Image.open(BytesIO(screenshot_bytes))
            
            image.thumbnail((THUMBNAIL_WIDTH, THUMBNAIL_HEIGHT), Image.Resampling.LANCZOS)
            
            thumbnail_buffer = BytesIO()
            image.save(thumbnail_buffer, format='PNG')
            thumbnail_buffer.seek(0)
            
            return thumbnail_buffer.getvalue()
        except Exception as e:
            logger.error(f"Error creating thumbnail: {e}")
            raise

    def close(self):
        if self.driver:
            self.driver.quit()


def generate_filename(url):
    url_hash = hashlib.md5(url.encode()).hexdigest()
    timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
    return f"screenshots/{timestamp}_{url_hash}.png"


def upload_to_s3(file_bytes, filename, content_type='image/png'):
    try:
        s3_client.put_object(
            Bucket=S3_BUCKET,
            Key=filename,
            Body=file_bytes,
            ContentType=content_type,
            ACL='public-read'
        )
        
        url = f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{filename}"
        logger.info(f"Uploaded screenshot to S3: {url}")
        return url
    except Exception as e:
        logger.error(f"Error uploading to S3: {e}")
        raise


screenshot_service = None


def get_screenshot_service():
    global screenshot_service
    if screenshot_service is None:
        screenshot_service = ScreenshotService()
    return screenshot_service


@app.route('/health', methods=['GET'])
def health_check():
    return jsonify({'status': 'healthy', 'service': 'screenshot-service'}), 200


@app.route('/screenshot', methods=['POST'])
def create_screenshot():
    try:
        data = request.get_json()
        
        if not data or 'url' not in data:
            return jsonify({'error': 'URL is required'}), 400
        
        url = data['url']
        
        if not url.startswith('http://') and not url.startswith('https://'):
            url = 'https://' + url
        
        create_thumbnail = data.get('thumbnail', True)
        
        logger.info(f"Processing screenshot request for: {url}")
        
        service = get_screenshot_service()
        
        screenshot_bytes = service.capture_screenshot(url)
        
        full_filename = generate_filename(url)
        full_url = upload_to_s3(screenshot_bytes, full_filename)
        
        response = {
            'success': True,
            'url': url,
            'screenshot_url': full_url,
            'timestamp': datetime.now().isoformat()
        }
        
        if create_thumbnail:
            thumbnail_bytes = service.create_thumbnail(screenshot_bytes)
            thumbnail_filename = full_filename.replace('.png', '_thumb.png')
            thumbnail_url = upload_to_s3(thumbnail_bytes, thumbnail_filename)
            response['thumbnail_url'] = thumbnail_url
        
        return jsonify(response), 200
        
    except Exception as e:
        logger.error(f"Error processing screenshot request: {e}")
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500


@app.route('/screenshot/batch', methods=['POST'])
def create_batch_screenshots():
    try:
        data = request.get_json()
        
        if not data or 'urls' not in data:
            return jsonify({'error': 'URLs array is required'}), 400
        
        urls = data['urls']
        create_thumbnail = data.get('thumbnail', True)
        
        if not isinstance(urls, list):
            return jsonify({'error': 'URLs must be an array'}), 400
        
        if len(urls) > 10:
            return jsonify({'error': 'Maximum 10 URLs per batch'}), 400
        
        service = get_screenshot_service()
        results = []
        
        for url in urls:
            try:
                if not url.startswith('http://') and not url.startswith('https://'):
                    url = 'https://' + url
                
                screenshot_bytes = service.capture_screenshot(url)
                full_filename = generate_filename(url)
                full_url = upload_to_s3(screenshot_bytes, full_filename)
                
                result = {
                    'success': True,
                    'url': url,
                    'screenshot_url': full_url
                }
                
                if create_thumbnail:
                    thumbnail_bytes = service.create_thumbnail(screenshot_bytes)
                    thumbnail_filename = full_filename.replace('.png', '_thumb.png')
                    thumbnail_url = upload_to_s3(thumbnail_bytes, thumbnail_filename)
                    result['thumbnail_url'] = thumbnail_url
                
                results.append(result)
                
            except Exception as e:
                logger.error(f"Error processing URL {url}: {e}")
                results.append({
                    'success': False,
                    'url': url,
                    'error': str(e)
                })
        
        return jsonify({
            'success': True,
            'results': results
        }), 200
        
    except Exception as e:
        logger.error(f"Error processing batch screenshot request: {e}")
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500


@app.route('/screenshot/cache/<url_hash>', methods=['GET'])
def get_cached_screenshot(url_hash):
    try:
        prefix = f"screenshots/"
        
        response = s3_client.list_objects_v2(
            Bucket=S3_BUCKET,
            Prefix=prefix
        )
        
        if 'Contents' not in response:
            return jsonify({'error': 'No cached screenshots found'}), 404
        
        matching_objects = [
            obj for obj in response['Contents']
            if url_hash in obj['Key']
        ]
        
        if not matching_objects:
            return jsonify({'error': 'Screenshot not found in cache'}), 404
        
        latest = max(matching_objects, key=lambda x: x['LastModified'])
        
        screenshot_url = f"https://{S3_BUCKET}.s3.{AWS_REGION}.amazonaws.com/{latest['Key']}"
        
        return jsonify({
            'success': True,
            'screenshot_url': screenshot_url,
            'cached_at': latest['LastModified'].isoformat()
        }), 200
        
    except Exception as e:
        logger.error(f"Error retrieving cached screenshot: {e}")
        return jsonify({
            'success': False,
            'error': str(e)
        }), 500


